  text-align: center;
}

.extra {
  text-align: left;
}

.cloze {
  background: rgba(135, 131, 120, 0.15);
  padding: 0.2em 0.4em;
  border-radius: 3px;
  font-weight: bold;
  color: blue;
}
.nightMode .cloze {
  color: lightblue;
}


